import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"基础武艺","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础武艺.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础武艺.md"}'),p={name:"4.资源分区/6.技艺及称号/武技类/武学基础/基础武艺.md"};function d(_,e,l,i,c,b){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"基础武艺",tabindex:"-1"},[n("基础武艺 "),a("a",{class:"header-anchor",href:"#基础武艺","aria-label":'Permalink to "基础武艺"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="基础武艺-1" tabindex="-1">基础武艺 <a class="header-anchor" href="#基础武艺-1" aria-label="Permalink to &quot;基础武艺&quot;">​</a></h1><p>基础武艺<br> D+1000<br> 前置：武学基础-战技入门<br> 注1：此技艺遵循【武学总纲】<br> 注2：此技艺联动【奠基内功】<br> 注3：此技艺可被任意遵循【武学总纲】的内功推动，获得相应效果。</p><p>刀枪剑戟，拳脚棍斧，万般兵器不一而足，此武艺之浩瀚无有穷也，人力难尽，而用着唯拳与所持，故著此法，为后来者奠基所用。</p><p>修习此法，将开始：<br> *劲力修行：修习者已学会劲道的收发之技，可尚且不能归一如意，由此，修习者的天生武器将增加1L的伤害，在经历两场影片后修至大成，此伤害变为3L。<br> *武艺修行：修习者的武艺技巧已初窥门径，每经历一场影片，修习者武艺都将得到小幅度提升，其使用天生武器及最擅长的武器攻击时将都增加1点技艺加值。</p><p>并习得：<br> *明劲：修习者使用内力加持攻击，消耗一点内力，使用本次近战攻击刚猛无匹，因此获得一点威猛。</p><p>如修习者还习有《奠基内功》，则还可通过其练就：</p><p>*劲气一体：修习者的内力被劲道合，使其更好地掌握内力，可提升一点智力属性。你可以消耗一缕内功修为再次获得提升。<br> *百里通识：修习者的耳目被内力加持，使其更好地了解环境，可提升一点感知属性。你可以消耗一缕内功修为再次获得提升<br> *武者之心：修习者的意志被修炼磨砺，使其决意更甚，可提升一点决心属性。你可以消耗一缕内功修为再次获得提升。<br> 此外，若修习者付出1XP，可进行武艺精研，触类旁通：<br> *百武精通：修习者经过刻苦修炼，精一法而通万法，【武艺修行】的效果扩展至所有武器。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',9)])])}const f=r(p,[["render",d]]);export{m as __pageData,f as default};
